// INPUT PARSER - Project 3 Competitor Monitoring
// Extracts category + optional focus keyword from chat input.
// Products for each retailer are pulled by category from the program's data server.

const input = $input.first().json.chatInput || '';

const categories = [
  { key: 'area_rug',       displayName: 'Area Rug',       patterns: ['area rug', 'area rugs'] },
  { key: 'outdoor_rug',    displayName: 'Outdoor Rug',    patterns: ['outdoor rug', 'outdoor rugs', 'patio rug', 'patio rugs'] },
  { key: 'hallway_runner', displayName: 'Hallway Runner', patterns: ['hallway runner', 'runner rug', 'hall runner', 'runners', 'hallway runners'] },
  { key: 'shag_rug',       displayName: 'Shag Rug',       patterns: ['shag rug', 'shag rugs', 'shaggy rug', 'shaggy rugs'] },
];

const lowerInput = input.toLowerCase();
let detectedCategory = null;
for (const cat of categories) {
  for (const pattern of cat.patterns) {
    if (lowerInput.includes(pattern)) {
      detectedCategory = cat;
      break;
    }
  }
  if (detectedCategory) break;
}

// Optional focus keyword (e.g. "focus: washable")
const focusMatch = input.match(/focus\s*:\s*([^\n]+)/i);
const focus = focusMatch ? focusMatch[1].trim() : '';

const hasCategory = !!detectedCategory;
const categoryKey = detectedCategory ? detectedCategory.key : null;
const categoryDisplayName = detectedCategory ? detectedCategory.displayName : null;

return [{
  json: {
    category: categoryKey,
    categoryKey,
    categoryDisplayName,
    focus,
    hasValidInput: hasCategory,
    errorReason: hasCategory ? null : 'no_category',
    originalInput: input,
    parsedAt: new Date().toISOString(),
  }
}];

// Reshape FastAPI response to the legacy shape that downstream consumers expect.
const r = $input.first().json;
const products = r.products || [];
return [{
  json: {
    wayfair_products: products.map(p => ({
      url: p.url,
      name: p.name,
      price: p.price,
      details: p.details || [],
      pattern: p.pattern || '',
      image_url: p.image_url || '',
      rating: p.rating || '',
      review_count: p.review_count || '',
      scraped_at: r.scraped_at || new Date().toISOString(),
    })),
    totalWayfair: products.length,
    totalProducts: products.length,
    scrapedAt: r.scraped_at || new Date().toISOString(),
  },
}];

// Reshape FastAPI response to the legacy shape that downstream consumers expect.
const r = $input.first().json;
const products = r.products || [];
return [{
  json: {
    amazonProducts: products.map(p => ({
      url: p.url,
      name: p.name,
      price: p.price,
      details: p.details || [],
      pattern: p.pattern || '',
      image_url: p.image_url || '',
      rating: p.rating || '',
      review_count: p.review_count || '',
      scraped_at: r.scraped_at || new Date().toISOString(),
    })),
    totalAmazonProducts: products.length,
    totalProducts: products.length,
    scrapedAt: r.scraped_at || new Date().toISOString(),
  },
}];

// Reshape FastAPI response to the legacy shape that downstream consumers expect.
const r = $input.first().json;
const products = r.products || [];
return [{
  json: {
    walmartProducts: products.map(p => ({
      url: p.url,
      name: p.name,
      price: p.price,
      details: p.details || [],
      pattern: p.pattern || '',
      image_url: p.image_url || '',
      rating: p.rating || '',
      review_count: p.review_count || '',
      scraped_at: r.scraped_at || new Date().toISOString(),
    })),
    totalWalmartProducts: products.length,
    totalProducts: products.length,
    scrapedAt: r.scraped_at || new Date().toISOString(),
  },
}];

// SCOPE GENERATOR - No AI, just JavaScript
// Generates Section 2: Scope of Research

const wayfairData = $('Reshape Wayfair Response').first().json;
const amazonData = $('Reshape Amazon Response').first().json;
let walmartData = {};
try { walmartData = $('Reshape Walmart Response').first().json || {}; } catch(e) {}
const inputData = $('Input Parser').first().json;

const category = inputData.categoryDisplayName || 'Rugs';
const amazonProductCount = amazonData.amazonProducts?.length || amazonData.totalProducts || 0;
const wayfairProductCount = wayfairData.wayfair_products?.length || 0;
const walmartProductCount = walmartData.walmartProducts?.length || walmartData.totalProducts || 0;

const scopeHtml = `
<section class="scope-section">
  <h2>Scope of Research</h2>
  <div class="scope-grid">
    <div class="scope-card">
      <h4>Category Analyzed</h4>
      <p class="scope-value">${category}</p>
    </div>
    <div class="scope-card">
      <h4>Competitors Reviewed</h4>
      <ul>
        <li><strong>Amazon</strong> - ${amazonProductCount} products analyzed</li>
        <li><strong>Walmart</strong> - ${walmartProductCount} products analyzed</li>
        <li><strong>Wayfair</strong> - ${wayfairProductCount} products (baseline)</li>
      </ul>
    </div>
    <div class="scope-card">
      <h4>Data Sources</h4>
      <ul>
        <li>Product listings & pricing</li>
        <li>Customer reviews & ratings</li>
        <li>Product features & specifications</li>
      </ul>
    </div>
    <div class="scope-card">
      <h4>Report Generated</h4>
      <p class="scope-value">${new Date().toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' })}</p>
    </div>
  </div>
</section>
`;

return [{
  json: {
    section: 'scope',
    html: scopeHtml,
    metadata: {
      category,
      amazonProductCount,
      walmartProductCount,
      wayfairProductCount,
      generatedAt: new Date().toISOString()
    }
  }
}];

